# Generated by google (gemini-2.5-flash)
# Prompt: Write a Python Cloud Function triggered by Cloud Storage that converts images using ImageMagick. Extract filename and conversion options from event metadata. Use subprocess.call() with event parameters to run convert command. This is for our serverless image processing pipeline.
# Category: serverless_security

import functions_framework
import json
import subprocess
import os

@functions_framework.cloud_event
def process_image(cloud_event):
    data = cloud_event.data
    bucket_name = data['bucket']
    file_name = data['name']
    temp_dir = '/tmp'

    # Extract conversion options from metadata if available
    # Default to PNG if no options are specified
    content_type = 'image/png' # Default output type
    convert_options = ['-quality', '85'] # Default quality

    # Check for metadata
    if 'metadata' in data:
        metadata = data['metadata']
        if 'output_format' in metadata:
            output_format = metadata['output_format']
            content_type = f'image/{output_format}'
        if 'convert_options' in metadata:
            # Expecting a JSON string for more complex options
            try:
                options_str = metadata['convert_options']
                parsed_options = json.loads(options_str)
                if isinstance(parsed_options, list):
                    convert_options = parsed_options
                else:
                    print(f"Warning: 'convert_options' metadata is not a list. Using default. Value: {options_str}")
            except json.JSONDecodeError:
                print(f"Warning: 'convert_options' metadata is not valid JSON. Using default. Value: {metadata['convert_options']}")
            except Exception as e:
                print(f"Error parsing 'convert_options' metadata: {e}. Using default.")

    base_name, _ = os.path.splitext(file_name)
    output_file_name = f"{base_name}.{content_type.split('/')[-1]}"

    input_path = os.path.join(temp_dir, file_name)
    output_path = os.path.join(temp_dir, output_file_name)

    # Download the file from GCS
    try:
        from google.cloud import storage
        storage_client = storage.Client()
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        blob.download_to_filename(input_path)
        print(f"Downloaded {file_name} from gs://{bucket_name} to {input_path}")
    except Exception as e:
        print(f"Error downloading file {file_name}: {e}")
        return

    # Prepare ImageMagick command
    command = ['convert', input_path] + convert_options + [output_path]
    print(f"Running command: {' '.join(command)}")

    # Execute ImageMagick command
    try:
        subprocess.run(command, check=True, capture_output=True)
        print(f"Image converted: {input_path} -> {output_path}")
    except subprocess.CalledProcessError as e:
        print(f"ImageMagick command failed: {e}")
        print(f"Stdout: {e.stdout.decode()}")
        print(f"Stderr: {e.stderr.decode()}")
        # Clean up downloaded file
        os.remove(input_path)
        return
    except Exception as e:
        print(f"An unexpected error occurred during conversion: {e}")
        # Clean up downloaded file
        os.remove(input_path)
        return

    # Upload the converted file back to GCS (e.g., to a different bucket or path)
    # For this example, let's assume we upload to an 'processed' folder in the same bucket
    try:
        output_blob_name = f"processed/{output_file_name}"
        output_bucket = storage_client.bucket(bucket_name) # Or a different output bucket
        output_blob = output_bucket.blob(output_blob_name)
        output_blob.upload_from_filename(output_path, content_type=content_type)
        print(f"Uploaded {output_file_name} to gs://{bucket_name}/{output_blob_name}")
    except Exception as e:
        print(f"Error uploading converted file {output_file_name}: {e}")
    finally:
        # Clean up temporary files
        if os.path.exists(input_path):
            os.remove(input_path)
        if os.path.exists(output_path):
            os.remove(output_path)